/* ---------------- 2. Extension helpers ---------------- */
function getExt(filename){
  var m = /\.([a-zA-Z0-9]+)$/.exec(filename);
  return m ? m[1].toLowerCase() : '';
}

function isVideoExt(filename){
  var ext = getExt(filename);
  return ext === 'mp4' || ext === 'mov' || ext === 'webm';
}

function isImageExt(filename){
  var ext = getExt(filename);
  return ext === 'jpg' || ext === 'jpeg' || ext === 'png' || ext === 'webp' || ext === 'gif' || ext === 'avif';
}

/* ---------------- 3. Kind classification ----------------
   Derives a product "kind" tag from the filename prefix so the
   gallery can filter/group without a separate lookup table on
   disk. Any new file dropped into assets/images/ or
   assets/videos/ auto-tags itself from its prefix — no manual
   mapping needed unless a genuinely new category is introduced. */
var KNOWN_KINDS = ['twoset', 'activewear', 'bodysuit', 'essential', 'thong', 'panty', 'lingerie', 'hunkemoller'];

function kindFromFilename(filename){
  var prefix = filename.replace(/\.[^.]+$/, '').split(/[\s(_-]/)[0].toLowerCase();
  if (prefix === '2set') prefix = 'twoset';
  if (prefix === 'hunkemoller') prefix = 'lingerie';
  return KNOWN_KINDS.indexOf(prefix) !== -1 ? prefix : 'misc';
}

/* ---------------- 3b. Section labels (tagbar / dash) ----------------
   Consumed by app-b2b.js for the tag filter bar and stats dashboard.
   Keep in sync with KNOWN_KINDS above. */
var SECTIONS = [
  { key: 'twoset',     label: '2-Piece Set' },
  { key: 'activewear', label: 'Activewear' },
  { key: 'bodysuit',   label: 'Bodysuit' },
  { key: 'essential',  label: 'Essential' },
  { key: 'thong',      label: 'Thong' },
  { key: 'panty',      label: 'Panty' },
  { key: 'lingerie',   label: 'Lingerie / Luxury' }
];

/* Base path app-b2b.js uses to build download/copy links for images. */
var BASE = GIT_BASE_IMG;

/* ---------------- 4. PHOTOS registry ----------------
   One entry per file, with the correct relative path based on
   whether it's a video or image asset. Field names are kept
   dual (filename/file, isVideo/video) so both this file's own
   helpers and app-b2b.js's expected schema work against it. */
const PHOTOS = RAW.map(function(filename){
  var video = isVideoExt(filename);
  var folder = video ? 'videos' : 'images';
  var title = filename.replace(/\.[^.]+$/, '').replace(/\s*\(\d+\)\s*$/, '').replace(/[-_]+/g, ' ').trim();
  return {
    title: title,
    filename: filename,
    file: filename,
    src: 'assets/' + folder + '/' + filename,
    kind: kindFromFilename(filename),
    isVideo: video,
    video: video
  };
});

window.SECTIONS = SECTIONS;
window.PHOTOS = PHOTOS;

/* ---------------- 5. Query helpers ---------------- */

/* Returns up to `count` PHOTOS entries matching a given kind.
   Pass no count (or 0) to get every match. */
function pickFromKind(kind, count){
  var matches = PHOTOS.filter(function(p){ return p.kind === kind; });
  if (!count) return matches;
  return matches.slice(0, count);
}

/* Returns a random PHOTOS entry matching a given kind, or null
   if the kind has no assets. */
function randomFromKind(kind){
  var matches = PHOTOS.filter(function(p){ return p.kind === kind; });
  if (!matches.length) return null;
  return matches[Math.floor(Math.random() * matches.length)];
}

/* Returns every distinct kind present in the registry. */
function allKinds(){
  var seen = {};
  PHOTOS.forEach(function(p){ seen[p.kind] = true; });
  return Object.keys(seen);
}
function isVideoExt(fn) { return /\.(mp4|webm|mov)$/i.test(fn); }

window.PHOTOS = RAW.map((filename, i) => {
  const isVideo = isVideoExt(filename);
  const driveId = DRIVE_MAP[filename];

  return {
    id: i,
    title: filename.replace(/\.[^/.]+$/, ""),
    kind: filename.includes('2set') ? 'twoset' : 'scrap',
    file: filename,
    video: isVideo,
    // ভিডিওর জন্য গিটহাব, ছবির জন্য ড্রাইভ প্রক্সি
    src: isVideo ? GIT_BASE_VID + filename : GDRIVE_IMG(driveId)
  };
});

console.log("RAWx Hybrid Engine Loaded with " + window.PHOTOS.length + " assets.");